import React, { useState, useEffect } from 'react';
import {
  Box, TextField, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Typography, Button
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';

function SearchPet() {
  const [isLoaded, setIsLoaded] = useState(false);
  const [pets, setPets] = useState([]);
  const [searchResults, setSearchResults] = useState([]);
  const [search, setSearch] = useState('');

  function fetchPets() {
    fetch("http://localhost:3001/api?act=getall")
      .then(res => res.json())
      .then((result) => {
        setIsLoaded(true);
        setPets(result);
        setSearchResults(result); // Initialize search results with all pets
      });
  }

  useEffect(() => {
    fetchPets();
  }, []);

  useEffect(() => {
    const filteredPets = pets.filter((pet) => 
      pet.animal.toLowerCase().includes(search.toLowerCase()) ||
      pet.description.toLowerCase().includes(search.toLowerCase()) ||
      pet.age.toString().includes(search) ||
      pet.price.toString().includes(search)
    );
    setSearchResults(filteredPets);
  }, [search, pets]);

  return (
    <div>
      <TextField
        id="search"
        label="Search"
        variant="outlined"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />
      {isLoaded ? (
        <Box sx={{ m: 4 }}>
          <TableContainer component={Paper}>
            <Table aria-label="simple table">
              <TableHead>
                <TableRow>
                  <TableCell>Animal</TableCell>
                  <TableCell>Description</TableCell>
                  <TableCell>Age</TableCell>
                  <TableCell>Price</TableCell>
                  <TableCell>Delete</TableCell>
                  <TableCell>Update</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {searchResults.map((pet) => (
                  <TableRow key={pet.id}>
                    <TableCell>{pet.animal}</TableCell>
                    <TableCell>{pet.description}</TableCell>
                    <TableCell>{pet.age}</TableCell>
                    <TableCell>{pet.price}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        </Box>
      ) : (
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>Loading...</Box>
      )}
    </div>
  );
}

export default SearchPet;
